INSERT INTO Movies (Id, Title, ReleaseYear, Rating, Duration, PosterUrl, Description, Actors, AgeRating, BackdropImageUrl, Director, Tagline, TmdbId)VALUES (4, N'Coraline', 2009, 7.909, 100, N'https://www.themoviedb.org/t/p/w1280//4jeFXQYytChdZYE9JYO7Un87IlW.jpg', N'Wandering her rambling old house in her boring new town, 11-year-old Coraline discovers a hidden door to a strangely idealized version of her life. In order to stay in the fantasy, she must make a frighteningly real sacrifice.', N'Dakota Fanning, Teri Hatcher, Jennifer Saunders, Dawn French, Keith David, John Hodgman, Robert Bailey Jr., Ian McShane, Aankha Neal, George Selick, Hannah Kaiser, Harry Selick, Marina Budovsky, Emerson Tenney, Jerome Ranft, Christopher Murrie, Jeremy Ryder, Carolyn Crawford, Yona Prost, John Linnell', N'11', N'https://www.themoviedb.org/t/p/w1280//hofnlIyF6bePkgQOpcuRWLvzf15.jpg', N'Henry Selick', N'Be careful what you wish for.', 14836);
INSERT INTO Movies (Id, Title, ReleaseYear, Rating, Duration, PosterUrl, Description, Actors, AgeRating, BackdropImageUrl, Director, Tagline, TmdbId) VALUES (5, N'Midsommar', 2019, 7.149, 147, N'https://www.themoviedb.org/t/p/w1280//7LEI8ulZzO5gy9Ww2NVCrKmHeDZ.jpg', N'Several friends travel to Sweden to study as anthropologists a summer festival that is held every ninety years in the remote hometown of one of them. What begins as a dream vacation in a place where the sun never sets, gradually turns into a dark nightmare as the mysterious inhabitants invite them to participate in their disturbing festive activities.', N'Florence Pugh, Jack Reynor, William Jackson Harper, Will Poulter, Vilhelm Blomgren, Isabelle Grill, Gunnel Fred, Ellora Torchia, Archie Madekwe, Henrik Norlén, Agnes Westerlund Rase, Julia Ragnarsson, Mats Blomgren, Lars Väringer, Anna Åström, Hampus Hallberg, Liv Mjönes, Louise Peterhoff, Katarina Weidhagen, Björn Andrésen, Tomas Engström, Dag Andersson, Lennart R. Svensson, Anders Beckman, Rebecka Johnston, Tove Skeidsvoll, Anders Back, Anki Larsson, Levente Puczkó-Smith, Frans Cavallin Rosengarten, Vilmos Kolba, Mihály Kaszás, Gabi Fón, Zsolt Bojári, Klaudia Csányi, Anna Berentzen, Austin R. Grant, Ari Aster', N'15', N'https://www.themoviedb.org/t/p/w1280//pYgj8e2Y6RufnSyOA6OnzmxFXxZ.jpg', N'Ari Aster', N'Let the festivities begin.', 530385);
