INSERT INTO Movies (Id, Title, ReleaseYear, Rating, Duration, PosterUrl, Description, Actors, AgeRating, BackdropImageUrl, Director, Tagline, TmdbId) VALUES (10, N'The Thing', 2011, 6.233, 103, N'https://www.themoviedb.org/t/p/w1280//dmn2nVo8h7LMnk694JxCRIwK06p.jpg', N'When paleontologist Kate Lloyd travels to an isolated outpost in Antarctica for the expedition of a lifetime, she joins an international team that unearths a remarkable discovery. Their elation quickly turns to fear as they realize that their experiment has freed a mysterious being from its frozen prison. Paranoia spreads like an epidemic as a creature that can mimic anything it touches will pit human against human as it tries to survive and flourish in this spine-tingling thriller.', N'Mary Elizabeth Winstead, Joel Edgerton, Ulrich Thomsen, Eric Christian Olsen, Adewale Akinnuoye-Agbaje, Paul Braunstein, Trond Espen Seim, Kim Bubbs, Jørgen Langhelle, Jan Gunnar Røise, Stig Henrik Hoff, Kristofer Hivju, Jo Adrian Haavind, Carsten Bjørnlund, Jonathan Walker, Ole Martin Aune Nilsen, Michael Brown', N'15', N'https://www.themoviedb.org/t/p/w1280//qgSlGJurPzgSHKYlqBiDmr3vjrc.jpg', N'Matthijs van Heijningen Jr.', N'It''s not human. Yet.', 60935);
