INSERT INTO Movies (Id, Title, ReleaseYear, Rating, Duration, PosterUrl, Description, Actors, AgeRating, BackdropImageUrl, Director, Tagline, TmdbId) VALUES (12, N'Tangled', 2010, 7.612, 100, N'https://www.themoviedb.org/t/p/w1280//ym7Kst6a4uodryxqbGOxmewF235.jpg', N'Feisty teenager Rapunzel, who has long and magical hair, wants to go and see sky lanterns on her eighteenth birthday, but she''s bound to a tower by her overprotective mother. She strikes a deal with Flynn Rider, a charming wanted thief, and the duo set off on an action-packed escapade.', N'Mandy Moore, Zachary Levi, Donna Murphy, Ron Perlman, M.C. Gainey, Jeffrey Tambor, Brad Garrett, Paul F. Tompkins, Richard Kiel, Delaney Rose Stein, Nathan Greno, Byron Howard, Tim Mertens, Michael Bell, Bob Bergen, Susanne Blakeslee, June Christopher, Roy Conli, David Cowgill, Terri Douglas, Chad Einbinder, Pat Fraley, Eddie Frierson, Jackie Gonneau, Nicholas Guest, Bridget Hoffman, Daniel Kaz, Anne Lockhart, Mona Marshall, Scott Menville, Laraine Newman, Paul Pape, Lynwood Robinson, Fred Tatasciore, Hynden Walch, Kari Wahlgren', N'7', N'https://www.themoviedb.org/t/p/w1280//cWczNud8Y8i8ab0Z4bxos4myWYO.jpg', N'Byron Howard', N'They''re taking adventure to new lengths.', 38757);
INSERT INTO Movies (Id, Title, ReleaseYear, Rating, Duration, PosterUrl, Description, Actors, AgeRating, BackdropImageUrl, Director, Tagline, TmdbId) VALUES (13, N'How to Train Your Dragon', 2010, 7.859, 98, N'https://www.themoviedb.org/t/p/w1280//ygGmAO60t8GyqUo9xYeYxSZAR3b.jpg', N'As the son of a Viking leader on the cusp of manhood, shy Hiccup Horrendous Haddock III faces a rite of passage: he must kill a dragon to prove his warrior mettle. But after downing a feared dragon, he realizes that he no longer wants to destroy it, and instead befriends the beast – which he names Toothless – much to the chagrin of his warrior father.', N'Jay Baruchel, Gerard Butler, Craig Ferguson, America Ferrera, Jonah Hill, Christopher Mintz-Plasse, T.J. Miller, Kristen Wiig, Robin Atkin Downes, Philip McGrade, Kieron Elliott, Ashley Jensen, David Tennant, Randy Thom', N'7', N'https://www.themoviedb.org/t/p/w1280//59vDC1BuEQvti24OMr0ZvtAK6R1.jpg', N'Chris Sanders', N'What started as fire and fury will become friendship.', 10191);
INSERT INTO Movies (Id, Title, ReleaseYear, Rating, Duration, PosterUrl, Description, Actors, AgeRating, BackdropImageUrl, Director, Tagline, TmdbId) VALUES (14, N'Moana', 2016, 7.566, 107, N'https://www.themoviedb.org/t/p/w1280//9tzN8sPbyod2dsa0lwuvrwBDWra.jpg', N'In Ancient Polynesia, when a terrible curse incurred by Maui reaches an impetuous Chieftain''s daughter''s island, she answers the Ocean''s call to seek out the demigod to set things right.', N'Auliʻi Cravalho, Dwayne Johnson, Rachel House, Temuera Morrison, Jemaine Clement, Nicole Scherzinger, Alan Tudyk, Louise Bush, Oscar Kightley, Troy Polamalu, Puanani Cravalho, Lin-Manuel Miranda, Christopher Jackson', N'7', N'https://www.themoviedb.org/t/p/w1280//iYLKMV7PIBtFmtygRrhSiyzcVsF.jpg', N'John Musker', N'The ocean is calling.', 277834);
INSERT INTO Movies (Id, Title, ReleaseYear, Rating, Duration, PosterUrl, Description, Actors, AgeRating, BackdropImageUrl, Director, Tagline, TmdbId) VALUES (15, N'Aladdin', 1992, 7.654, 91, N'https://www.themoviedb.org/t/p/w1280//eLFfl7vS8dkeG1hKp5mwbm37V83.jpg', N'In the boorish city of Agrabah, kind-hearted street urchin Aladdin and Princess Jasmine fall in love, although she can only marry a prince. He and power-hungry Grand Vizier Jafar vie for a magic lamp that can fulfill their wishes.', N'Scott Weinger, Robin Williams, Linda Larkin, Jonathan Freeman, Gilbert Gottfried, Douglas Seale, Frank Welker, Brad Kane, Lea Salonga, Bruce Adler, Charlie Adler, Jack Angel, Corey Burton, Philip L. Clarke, Jim Cummings, Jennifer Darling, Debi Derryberry, Bruce Gooch, Jerry Houser, Vera Lockwood, Sherry Lynn, Mickie McGowan, Patrick Pinney, Phil Proctor', N'7', N'https://www.themoviedb.org/t/p/w1280//nenJjvfe2Eq8uBMXFJnWj5mw4bi.jpg', N'John Musker', N'Imagine if you had three wishes, three hopes, three dreams and they all could come true.', 812);
