INSERT INTO Movies (Id, Title, ReleaseYear, Rating, Duration, PosterUrl, Description, Actors, AgeRating, BackdropImageUrl, Director, Tagline, TmdbId) VALUES (17, N'Despicable Me', 2010, 7.258, 95, N'https://www.themoviedb.org/t/p/w1280//b1BT309QWjtFUlJPLmXmrcHOWEL.jpg', N'Gru is a supervillain determined to prove he’s the greatest by stealing the Moon. To pull off his plan, he adopts three orphaned girls—Margo, Edith, and Agnes—intending to use them as part of his scheme. However, as Gru bonds with the girls, his cold, villainous exterior begins to melt.', N'Steve Carell, Jason Segel, Miranda Cosgrove, Dana Gaier, Elsie Fisher, Russell Brand, Julie Andrews, Will Arnett, Kristen Wiig, Pierre Coffin, Chris Renaud, Jemaine Clement, Jack McBrayer, Danny McBride, Mindy Kaling, Rob Huebel, Ken Daurio, Ken Jeong, Charles Bright, Katie Leigh, Ranjani Brow, Scott Menville, Holly Dorff, Edie Mirman, Jackie Gonneau, Al Rodrigo, Wendy Hoffmann, Jakob Roston, James Kyson, John Hans Tester, Tony Lee, Debi Mae West', N'7', N'https://www.themoviedb.org/t/p/w1280//2XSeKDmIa2KxaiJy4J9e8FrIZhk.jpg', N'Pierre Coffin', N'Superbad. Superdad.', 20352);
