INSERT INTO Movies (Id, Title, ReleaseYear, Rating, Duration, PosterUrl, Description, Actors, AgeRating, BackdropImageUrl, Director, Tagline, TmdbId) VALUES (25, N'12 Angry Men', 1957, 8.561, 97, N'https://www.themoviedb.org/t/p/w1280//zhG3vKWyDRaZYoaww1UVAi29T9h.jpg', N'The defense and the prosecution have rested and the jury is filing into the jury room to decide if a young Spanish-American is guilty or innocent of murdering his father. What begins as an open and shut case soon becomes a mini-drama of each of the jurors'' prejudices and preconceptions about the trial, the accused, and each other.', N'Martin Balsam, John Fiedler, Lee J. Cobb, E.G. Marshall, Jack Klugman, Edward Binns, Jack Warden, Henry Fonda, Joseph Sweeney, Ed Begley, George Voskovec, Robert Webber, Rudy Bond, Tom Gorman, James Kelly, Billy Nelson, Walter Stocker, John Savoca', N'15', N'https://www.themoviedb.org/t/p/w1280//w4bTBXcqXc2TUyS5Fc4h67uWbPn.jpg', N'Sidney Lumet', N'It explodes like 12 sticks of dynamite!', 389);
