INSERT INTO Movies (Id, Title, ReleaseYear, Rating, Duration, PosterUrl, Description, Actors, AgeRating, BackdropImageUrl, Director, Tagline, TmdbId) VALUES (52, N'Taken', 2008, 7.406, 94, N'https://www.themoviedb.org/t/p/w1280//ognkaUSNgJe1a2pjB4UNdzEo5jT.jpg', N'Bryan Mills, a former government operative, is trying to reconnect with his teenage daughter Kim. After reluctantly agreeing with his ex-wife to let Kim go to Paris on vacation with a friend, his worst nightmare comes true. While on the phone with his daughter shortly after she arrives in Paris, she and her friend are abducted by a gang of human traffickers. Working against the clock, Bryan relies on his extensive training and skills to track down the ruthless gang that abducted her and launch a one-man war to rescue his daughter.', N'Liam Neeson, Maggie Grace, Famke Janssen, Olivier Rabourdin, Leland Orser, Jon Gries, David Warshofsky, Holly Valance, Gérard Watkins, Arben Bajraktaraj, Xander Berkeley, Katie Cassidy, Radivoje Bukvić, Nicolas Giraud, Jalil Naciri, Goran Kostić, Camille Japy, Héléna Soubeyrand, Opender Singh, Nabil Massad, Michel Flash, Rubens Hyka, Valentin Kalaj, Christophe Kourotchkine, Anca Radici, Nathan Rippy, Tommy Spahija, Anatole Taubman, Mathieu Busson, Edwin Krüger, Fani Kolarova, Bertrand Treuil, Marc Amyot, Christy Reese, George Hertzberg, Ivette González, Thierry Stein, Don Abernathy, Michael Finn', N'15', N'https://www.themoviedb.org/t/p/w1280//lMRMjd9yJsZLyaT97eiURu2zVb4.jpg', N'Pierre Morel', N'They took his daughter. He''ll take their lives.', 8681);
