INSERT INTO Movies (Id, Title, ReleaseYear, Rating, Duration, PosterUrl, Description, Actors, AgeRating, BackdropImageUrl, Director, Tagline, TmdbId) VALUES (55, N'Back to the Future', 1985, 8.326, 116, N'https://www.themoviedb.org/t/p/w1280//vN5B5WgYscRGcQpVhHl6p9DDTP0.jpg', N'Eighties teenager Marty McFly is accidentally sent back in time to 1955, inadvertently disrupting his parents'' first meeting and attracting his mother''s romantic interest. Marty must repair the damage to history by rekindling his parents'' romance and - with the help of his eccentric inventor friend Doc Brown - return to 1985.', N'Michael J. Fox, Christopher Lloyd, Crispin Glover, Lea Thompson, Claudia Wells, Thomas F. Wilson, Marc McClure, Wendie Jo Sperber, George DiCenzo, Frances Lee McCain, James Tolkan, J.J. Cohen, Casey Siemaszko, Billy Zane, Harry Waters, Jr., Donald Fullilove, Lisa Freeman, Cristen Kauffman, Elsa Raven, Will Hare, Ivy Bethune, Jason Marin, Katherine Britton, Jason Hervey, Maia Brewton, Courtney Gains, Richard L. Duran, Jeff O''Haco, Johnny Green, Jamie Abbott, Norman Alden, Read Morgan, Sachi Parker, Robert Krantz, Gary Riley, Karen Petrasek, George Buck Flower, Tommy Thomas, Granville ''Danny'' Young, David Harold Brown, Lloyd L. Tolbert, Paul Hanson, Lee Brownfield, Robert DeLapp, Tony Pope, Charles L. Campbell, Huey Lewis, Hal Gausman, Deborah Harmon, Arthur Tovey, Tom Tangen, Tom Willett', N'11', N'https://www.themoviedb.org/t/p/w1280//5bzPWQ2dFUl2aZKkp7ILJVVkRed.jpg', N'Robert Zemeckis', N'He was never in time for his classes... He wasn''t in time for his dinner... Then one day... he wasn''t in his time at all.', 105);
